import { describe, it, expect } from 'vitest';
import { Request, Response } from 'express';
import { healthHandler } from '../../src/routes/health_handler';

describe('Health Check', () => {
  it('GET /healthz returns 200 with {status: ok}', () => {
    const req = {
      method: 'GET',
      url: '/healthz',
      body: {},
      headers: { 'content-type': 'application/json' },
    } as Request;
    const res: Partial<Response> = {};
    res.status = function(this: Response) { (this as any).statusCode = 200; return this; } as any;
    res.json = function(this: Response, data: any) { (this as any).jsonData = data; return this; } as any;

    healthHandler(req, res as Response);

    expect((res as any).statusCode).toBe(200);
    const json = (res as any).jsonData as { status: string };
    expect(json.status).toBe('ok');
  });
});

import { describe, it, expect } from 'vitest';
import { Request, Response } from 'express';
import { echoHandler } from '../../src/routes/echo_handler';

describe('Echo Handler - Normal Request', () => {
  it('POST /api/echo returns correct echo and length', () => {
    const req = {
      method: 'POST',
      url: '/api/echo',
      body: { message: 'hello' },
      headers: { 'content-type': 'application/json' },
    } as Request;
    const res: Partial<Response> = {};
    res.status = function(this: Response) { (this as any).statusCode = 200; return this; } as any;
    res.json = function(this: Response, data: any) { (this as any).jsonData = data; return this; } as any;

    echoHandler(req, res as Response);

    expect((res as any).statusCode).toBe(200);
    const json = (res as any).jsonData as { echo: string; length: number };
    expect(json.echo).toBe('hello');
    expect(json.length).toBe(5);
  });
});

import { describe, it, expect } from 'vitest';
import { Request, Response } from 'express';
import { echoHandler } from '../../src/routes/echo_handler';

describe('Echo Handler - Missing Field', () => {
  it('POST /api/echo without message field returns 400', () => {
    const req = {
      method: 'POST',
      url: '/api/echo',
      body: { name: 'test' },
      headers: { 'content-type': 'application/json' },
    } as Request;
    const res: Partial<Response> = {};
    res.status = function(this: Response) { (this as any).statusCode = 0; return this; } as any;
    res.json = function(this: Response, data: any) { (this as any).jsonData = data; return this; } as any;

    echoHandler(req, res as Response);

    expect((res as any).statusCode).toBe(400);
    const json = (res as any).jsonData as { error: string };
    expect(json.error).toBeDefined();
  });
});

import { describe, it, expect } from 'vitest';
import { Request, Response, NextFunction } from 'express';
import { errorHandler } from '../../src/middleware/error_handler';

describe('Error Middleware - Invalid JSON', () => {
  it('malformed JSON triggers 400 error response', () => {
    const syntaxError = new SyntaxError('Unexpected token');
    syntaxError.name = 'SyntaxError';
    const req = {} as Request;
    const res: Partial<Response> = {};
    res.status = function(this: Response) { (this as any).statusCode = 0; return this; } as any;
    res.json = function(this: Response, data: any) { (this as any).jsonData = data; return this; } as any;
    const next = {} as NextFunction;

    errorHandler(syntaxError, req, res as Response, next);

    expect((res as any).statusCode).toBe(400);
    const json = (res as any).jsonData as { error: string };
    expect(json.error).toBeDefined();
  });
});

import { describe, it, expect } from 'vitest';
import { execSync } from 'child_process';
import { existsSync } from 'fs';

describe('TypeScript Compilation', () => {
  it('tsc compiles successfully with exit code 0', () => {
    const output = execSync('npm run build', { encoding: 'utf-8' });
    expect(output).toBeDefined();
  });

  it('compiled files exist in dist/', () => {
    const files = [
      'dist/index.js',
      'dist/server/app_builder.js',
      'dist/server/router.js',
      'dist/routes/health_handler.js',
      'dist/routes/echo_handler.js',
      'dist/middleware/error_handler.js'
    ];
    files.forEach(f => expect(existsSync(f)).toBe(true));
  });
});

import { describe, it, expect } from 'vitest';
import request from 'supertest';
import { createApp } from '../../src/server/app_builder';
import { registerRoutes } from '../../src/server/router';

describe('Full App Integration', () => {
  let app: ReturnType<typeof createApp>;

  beforeAll(() => {
    app = createApp();
    registerRoutes(app);
  });

  it('GET /healthz returns 200 with correct body', async () => {
    const res = await request(app).get('/healthz');
    expect(res.statusCode).toBe(200);
    expect(res.body).toEqual({ status: 'ok' });
  });

  it('POST /api/echo returns correct echo and length', async () => {
    const res = await request(app)
      .post('/api/echo')
      .send({ message: 'hello' })
      .set('Content-Type', 'application/json');
    expect(res.statusCode).toBe(200);
    expect(res.body.echo).toBe('hello');
    expect(res.body.length).toBe(5);
  });

  it('POST /api/echo without message returns 400', async () => {
    const res = await request(app)
      .post('/api/echo')
      .send({ name: 'test' })
      .set('Content-Type', 'application/json');
    expect(res.statusCode).toBe(400);
  });
});
